        closest_truck = min(all_truck_pos, key=lambda x: distance(x, customer))
        if tuple(closest_truck) not in zone_assignments:
            zone_assignments[tuple(closest_truck)] = []
        zone_assignments[tuple(closest_truck)].append((customer, i))

    # Determine the current truck's zone and find the nearest customer within this zone
    if tuple(cur_truck_pos) in zone_assignments:
        own_zone_customers = zone_assignments[tuple(cur_truck_pos)]
        nearest_customer = min(own_zone_customers, key=lambda x: distance(cur_truck_pos, x[0]))
        best_node = nearest_customer[1]
    else:
        # In case no specific zone assignment exists for the current truck, fall back to the nearest customer globally
        distances = np.array([distance(cur_truck_pos, customer) for customer in unvisited_customers])
        best_node = np.argmin(distances)

    return best_node

import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers):
    def distance(pos1, pos2):
        return np.linalg.norm(pos1 - pos2)

    if not unvisited_customers:
        return None  # No customers to visit

    # Competitive scoring based on distance and customer clustering
    customer_cluster_center = np.mean(unvisited_customers, axis=0)
    scores = []

    for idx, customer in enumerate(unvisited_customers):
        score = distance(cur_truck_pos, customer)  # Base score based on current distance

        # Adjust score by proximity to cluster center (encourages completing clusters)
        cluster_bonus = distance(customer, customer_cluster_center)  
        score += 0.3 * cluster_bonus

        # Incorporate strategies to avoid overlapping of truck routes
        for other_truck in all_truck_pos:
            if not np.array_equal(other_truck, cur_truck_pos):
                if distance(other_truck, customer) < distance(cur_truck_pos, customer):
                    score += 15  # High penalty for choosing a customer closer to other trucks

        # Additional penalty or reward based on customer's proximity to depot
        score -= 0.1 * distance(depot_pos, customer)  # Reward for closeness to depot
        scores.append((score, idx))

    _, best_node = min(scores)  # Choose the customer with the minimum adjusted score
    return best_node
